def _load_mol_tokenizer_vocab_size() -> int:
    """Load the pure tokenizer constant without importing mol encoder deps."""
    tokenizer_path = Path(__file__).resolve().parents[1] / "modalities" / "mol" / "tokenizer.py"
    spec = importlib.util.spec_from_file_location("_qwenvl_mol_tokenizer_constants", tokenizer_path)
    if spec is None or spec.loader is None:
        raise ImportError(f"Could not load mol tokenizer constants from {tokenizer_path}")
    module = importlib.util.module_from_spec(spec)
    spec.loader.exec_module(module)
    return int(module.MOL_VOCAB_SIZE)


MOL_TOKENIZER_VOCAB_SIZE = _load_mol_tokenizer_vocab_size()


