class Qwen3VLRNAConfig(PretrainedConfig):
    """
    Configuration for the lightweight RNAConvFormer encoder and projector.

    The encoder is a small conv-stem + Transformer followed by a
    perceiver-style latent resampler that compresses variable-length RNA
    sequences into a fixed number of latent tokens (``num_latent_tokens``).

    RNA Output Format (LM mode):
      The RNA sequence in assistant response is formatted as:
      <|vision_start|>A|U|C|G|...|<|vision_end|>
      where each nucleotide and separator are individual tokens.
      This allows standard lm_head to predict RNA sequences via
      next-token prediction.
    """
    model_type = "qwen3_vl_rna"
    base_config_key = "rna_config"

    def __init__(
        self,
        rna_encoder_path: Optional[str] = None,
        rna_encoder_hidden_size: int = 512,
        rna_projector_hidden_size: Optional[int] = None,
        rna_vocab_size: int = 8,
        rna_max_seq_length: int = 2048,
        num_encoder_layers: int = 8,
        num_attention_heads: int = 8,
        conv_kernel_size: int = 7,
        num_latent_tokens: int = 16,
        dropout: float = 0.1,
        **kwargs,
    ):
        super().__init__(**kwargs)

        self.rna_encoder_path = rna_encoder_path
        self.rna_encoder_hidden_size = rna_encoder_hidden_size
        self.rna_projector_hidden_size = rna_projector_hidden_size or (4 * rna_encoder_hidden_size)
        self.rna_vocab_size = rna_vocab_size
        self.rna_max_seq_length = rna_max_seq_length
        self.num_encoder_layers = num_encoder_layers
        self.num_attention_heads = num_attention_heads
        self.conv_kernel_size = conv_kernel_size
        self.num_latent_tokens = num_latent_tokens
        self.dropout = dropout


