        self.embed_freq = embed_freq
        self.time_embed_dropout = float(time_embed_dropout)
        self.frame_interval = frame_interval
        self.qwenvl_dim = qwenvl_dim
        self.meteo_loss_type = meteo_loss_type
        self.meteo_loss_weight = meteo_loss_weight
        self.meteo_loss_coef = meteo_loss_coef
        self.lead_hour_scaling = lead_hour_scaling
        self.pl_chans = pl_chans
        self.meteo_data_path = meteo_data_path
        self.max_rollout_steps = max_rollout_steps
        self._attn_implementation = _attn_implementation


